private RealMatrix squareRoot(RealMatrix m) {
    final RealMatrix sqrt = m.copy();
    for (int i = 0; i < sqrt.getRowDimension(); i++) {
        sqrt.setEntry(i, i, FastMath.sqrt(sqrt.getEntry(i, i)));
    }
    return sqrt;
}

